mapper.select:
select from cook_posts p inner join cook_users u on u.id = p.user_id and u.deleted_at is null left join cook_recipes rr on rr.id = p.related_recipe_id and rr.deleted_at is null left join cook_recipe_versions rv on rv.id = rr.current_version_id and rv.deleted_at is null where p.deleted_at is null and p.user_id = #{userId}
and p.status = #{status}
order by p.updated_at desc, p.id desc

mapper.insert:
insert into cook_posts (
    user_id, content, visibility, media_ids_json, topic_codes_json, location, related_recipe_id,
    source_type, status
) values (
    #{userId}, #{content}, #{visibility}, #{mediaIdsJson}, #{topicCodesJson}, #{location},
    #{relatedRecipeId}, #{sourceType}, #{status}
)

mapper.update:
update cook_posts
set deleted_at = current_timestamp,
    updated_at = current_timestamp
where id = #{id}
  and user_id = #{userId}
  and deleted_at is null
